import Foundation
import Combine
import FactoryKit

extension Container {
    var activityDataRepository: Factory<ActivityDataRepository>{
        self { ActivityDataRepositoryImpl() }
            .singleton
    }
}

/// Репозиторий работы с Активностью (спектр Accum)
protocol ActivityDataRepository: SpectrumSettingsSetup {

    /// Издатель подключенного спектра
    var spectrumSubject: PassthroughSubject<SpectrumData, Never> { get }

    /// Запускает получение спектра
    func startSpectrumCollect()

    /// Останавливает получение спектра
    func cancelSpectrumCollect()
}

final class ActivityDataRepositoryImpl: ActivityDataRepository {

    enum Consts {
        static let firstDelay: Double = 2.0
        static let defaultDelay: Double = 4.0
    }

    @Injected(\.deviceManager) private var deviceManager

    var specFormatVersion = false
    var spectrumDisabled = false

    private var spectrumCollectTask: Task<Void, Error>?

    var spectrumSubject: PassthroughSubject<SpectrumData, Never> = .init()

    private var cancellable: Set<AnyCancellable> = .init()

    func startSpectrumCollect() {
        guard !spectrumDisabled else { return }
        guard spectrumCollectTask == nil else { return }
        spectrumCollectTask = Task {
            var delay = Consts.firstDelay
            repeat {
                try await sendSpectrumCommand()
                try await Task.sleep(seconds: delay)
                delay = Consts.defaultDelay
            } while !Task.isCancelled
        }
    }

    func cancelSpectrumCollect() {
        spectrumCollectTask?.cancel()
        spectrumCollectTask = nil
    }

    private func sendSpectrumCommand() async throws {
        let result = await deviceManager.send(command: SpectrumAccumCommand(specFormatVersion: specFormatVersion))
        if case .success(let response) = result {
            let spectrum = SpectrumData(
                time: response.time,
                coefficients: response.coefficients,
                countNeg: response.countNeg,
                pulses: response.pulses
            )
            spectrumSubject.send(spectrum)
        }
    }
}
