import Foundation
import FactoryKit

extension Container {
    var gapsRepository: Factory<GapsRepository> {
        self { GapsRepositoryImpl() }.singleton
    }
}

protocol GapsRepository {
    func fetchGaps(deviceId: String, start: Date) async -> [DateInterval]
}

final class GapsRepositoryImpl: GapsRepository {

    @Injected(\.eventsDatabaseManager) private var databaseManager

    func fetchGaps(deviceId: String, start: Date) async -> [DateInterval] {
        let events = await databaseManager.fetchEvents(
            deviceId: deviceId,
            start: start,
            types: [.powerOn, .powerOff, .lowBatteryPowerOff]
        )

        var gaps: [DateInterval] = []
        var offDate: Date? = nil

        // Если первое событие — powerOn, значит до него был разрыв от start
        if case .powerOn = events.first?.eventId {
            offDate = start
        }

        for (date, eventId) in events {
              switch eventId {
              case .powerOn:
                  guard let off = offDate else { continue }
                  gaps.append(DateInterval(start: off, end: date))
                  offDate = nil
              case .powerOff, .lowBatteryPowerOff:
                  offDate = date
              default:
                  break
              }
          }

        return gaps
    }
}

