import Foundation

protocol IsotopeService {

    func get(energy: Int16) -> IsotopeData?
}

final class IsotopeServiceImpl: IsotopeService {

    private enum Consts {
        static let bundleUrl = Bundle.main.url(forResource: "appIsotopes", withExtension: "json")
    }

    private lazy var isotopes: [Isotope] = {
        if let url = Consts.bundleUrl {
            do {
                let jsonData = try Data(contentsOf: url)
                let decoder = JSONDecoder()
                return try decoder.decode([Isotope].self, from: jsonData)
            } catch {
                Log.error(error)
                return []
            }
        } else {
            return []
        }
    }()

    func get(energy: Int16) -> IsotopeData? {
        if let isotope = isotopes
            .filter ({ $0.visibility == 5 })
            .min(by: { abs(Int16($0.energy) - energy) < abs(Int16($1.energy) - energy) }) {
            guard abs(Int16(isotope.energy) - energy) < 25 else { return nil }
            let energies: [Int16]
            if let chain = isotope.chain {
                energies = isotopes.filter({ $0.chain == chain }).map({ Int16($0.energy) })
            } else {
                energies = isotopes.filter({ $0.name == isotope.name }).map({ Int16($0.energy) })
            }
            return .init(isotope: isotope, energies: energies)
        }
        return nil
    }
}
