        do {
            let urlPath: String = Consts.urlHardnessFileName + model.family.postFix
            guard let bundleUrl = Bundle.main.url(forResource: urlPath, withExtension: Consts.urlHardnessFileExtension) else {
                throw HardnessIsotopeProviderError.invalidURL
            }
            let fileContent = try String(contentsOf: bundleUrl, encoding: .utf8)
            return fileContent
                .split(whereSeparator: \.isNewline)
                .map { $0.components(separatedBy: ";") }
                .compactMap { .init(fields: $0) }
        } catch {
            Log.error(error)
            return []
        }
    }
}

