//
//  ConfigurationRepository.swift
//  Radiacode
//
//  Created by Matvey Kozin on 25.07.2023.
//

import Foundation
import RegexBuilder
import FactoryKit

extension Container {
    var configurationParser: Factory<ConfigurationParser> {
        self { ConfigurationParserImpl() }
    }
}

protocol ConfigurationParser {

    /// Парсинг настроек
    /// - Parameter configuration: конфигурация
    /// - Returns: настройки
    func parse(configuration: ConfigurationCommand.Response) throws -> BluetoothDevice.ConfigurationSettings
}

final class ConfigurationParserImpl: ConfigurationParser {

    fileprivate enum ConfigurationError: String, Error {
        case invalidRange
        case indexOutOfBounds
    }

    private enum Consts {
        static let deviceParamsKey = "[DeviceParams]"
        static let specFormatVersionKey = "SpecFormatVersion"
        static let disableSpectrumKey = "DisableSpectrum"
        static let disableHardnessKey = "DisableHardness"
        static let framePeriodMSKey = "MinFrmPeriod_ms"
        static let maxCountRateKey = "CR_AlarmMax_cps"
        static let maxDoseRateKey = "DR_AlarmMax_R_h"
        static let maxDoseKey = "DS_AlarmMax_R"
        static let textASCIImaxSizeKey = "TextASCII_MaxSize"
        static let doseAlarmMultiplierKey = "DS_AlarmVsfrMul"
    }

    func parse(configuration: ConfigurationCommand.Response) throws -> BluetoothDevice.ConfigurationSettings {
        let parameters = configuration.string.components(separatedBy: ["\n"])
        do {
            let sections = try findSections(in: parameters)
            return fillConfiguration(sections)
        } catch {
            throw ConfigurationRepositoryError(description: error.rawValue, response: configuration.string)
        }
    }

    private func fillConfiguration(_ sections: [DeviceConfiguration.Section]) -> BluetoothDevice.ConfigurationSettings {
        let params = sections
               .first(where: { $0.name == Consts.deviceParamsKey })?
               .parameters ?? [:]

        return BluetoothDevice.ConfigurationSettings(
               specFormatVersion: params[Consts.specFormatVersionKey] == "1",
               disableSpectrum: params[Consts.disableSpectrumKey] == "1",
               disableHardness: params[Consts.disableHardnessKey] == "1",
               framePeriodMS: Int(params[Consts.framePeriodMSKey, default: "500"]) ?? 500,
               maxCountRate: decimalValue(for: Consts.maxCountRateKey, in: params),
               maxDoseRate: decimalValue(for: Consts.maxDoseRateKey, in: params).map { $0 * 10000 },
               maxDose: decimalValue(for: Consts.maxDoseKey, in: params).map { $0 * 10000 },
               textASCIImaxSize: Int(params[Consts.textASCIImaxSizeKey] ?? "") ?? 0,
               doseAlarmMultiplier: UInt32(params[Consts.doseAlarmMultiplierKey] ?? "") ?? 1,
               configurationGroups: sections.flatMap(\.groups)
           )
    }

    private func decimalValue(for key: String, in params: [String: String]) -> Decimal? {
        guard let value = params[key] else { return nil }
        return Decimal(string: value)
    }
}

private extension ConfigurationParserImpl {

    func findSections(in parameters: [String]) throws(ConfigurationError) -> [DeviceConfiguration.Section] {
        var sections: [DeviceConfiguration.Section] = []

        let sectionRegex = makeConfigurationRegex(prefix: "[", suffix: "]")
        let paramsAsString = parameters.joined(separator: "\n")
        let availableSections = paramsAsString.matches(of: sectionRegex)

        // Сохраним индексы секций в одном проходе
        let sectionIndices = availableSections.compactMap { section in
            parameters.firstIndex(of: String(section.output.0))
        }

        for (currentIndex, sectionStart) in sectionIndices.enumerated() {
            let sectionEnd: Array<String>.Index

            if currentIndex + 1 < sectionIndices.count {
                sectionEnd = sectionIndices[currentIndex + 1]
            } else {
                sectionEnd = parameters.endIndex
            }

            let sectionDataStartIndex = sectionStart + 1

            guard sectionDataStartIndex <= sectionEnd,
                  sectionEnd <= parameters.endIndex else {
                throw .invalidRange
            }

            let partArray = Array(parameters[sectionDataStartIndex..<sectionEnd])

            let groups = try findGroups(in: partArray)
            let params = try readParams(
                partArray,
                startIndexGroups: groups.startIndexGroups ?? (sectionEnd - sectionDataStartIndex)
            )

            let newSection = DeviceConfiguration.Section(
                name: String(availableSections[currentIndex].output.0),
                parameters: params,
                groups: groups.list
            )

            sections.append(newSection)
        }

        return sections
    }

    func findGroups(in parameters: [String]) throws(ConfigurationError) -> (list: [DeviceConfiguration.Group], startIndexGroups: Int?)  {
        var startIndexGroups: Int?
        var groups: [DeviceConfiguration.Group] = []

        let groupRegex = makeConfigurationRegex(prefix: "[[", suffix: "]]")
        let paramsAsString = parameters.joined(separator: "\n")
        let availableGroups = paramsAsString.matches(of: groupRegex)

        // Сохраним индексы групп в одном проходе
         let groupIndices = availableGroups.compactMap { group in
             parameters.firstIndex(of: String(group.output.0))
         }

        for (currentIndex, groupStart) in groupIndices.enumerated() {
            let groupEnd: Array<String>.Index

            if currentIndex + 1 < groupIndices.count {
                groupEnd = groupIndices[currentIndex + 1]
            } else {
                groupEnd = parameters.endIndex
            }

            if startIndexGroups == nil {
                startIndexGroups = groupStart
            }

            let groupDataStartIndex = groupStart + 1

            guard groupDataStartIndex <= groupEnd,
                  groupEnd <= parameters.endIndex else {
                throw .invalidRange
            }

            let partArray = Array(parameters[groupDataStartIndex..<groupEnd])

            let channels = try findChannels(in: partArray)
            let params = try readParams(
                partArray,
                startIndexGroups: channels.startIndexChannels ?? (groupEnd - groupDataStartIndex)
            )

            let newGroup = DeviceConfiguration.Group(
                name: String(availableGroups[currentIndex].output.1),
                parameters: params,
                channels: channels.list
            )

            groups.append(newGroup)
        }
        return (list: groups, startIndexGroups: startIndexGroups)
    }

    func findChannels(in parameters: [String]) throws(ConfigurationError) -> (list: [DeviceConfiguration.Channel],  startIndexChannels: Int?) {
        var startIndexChannels: Int?
        var channels: [DeviceConfiguration.Channel] = []

        let channelRegex = makeConfigurationRegex(prefix: "[[[", suffix: "]]]")
        let paramsAsString = parameters.joined(separator: "\n")
        let availableChannels = paramsAsString.matches(of: channelRegex)

        // Сохраняем индексы каналов
        let channelIndices = availableChannels.compactMap { channel in
            parameters.firstIndex(of: String(channel.output.0))
        }

        for (currentIndex, channelStart) in channelIndices.enumerated() {
            let channelEnd: Array<String>.Index

            if currentIndex + 1 < channelIndices.count {
                channelEnd = channelIndices[currentIndex + 1]
            } else {
                channelEnd = parameters.endIndex
            }

            if startIndexChannels == nil {
                startIndexChannels = channelStart
            }

            let channelStartIndex = channelStart + 1

            guard channelStartIndex <= channelEnd,
                  channelEnd <= parameters.endIndex else {
                throw .invalidRange
            }

            let partArray = Array(parameters[channelStartIndex..<channelEnd])
            let params = try readParams(partArray, startIndexGroups: channelEnd - channelStartIndex)

            let newChannel = DeviceConfiguration.Channel(
                channelId: params["Id"] ?? "",
                parameters: params
            )
            channels.append(newChannel)
        }

        return (list: channels, startIndexChannels: startIndexChannels)
    }

    private func readParams(_ parameters: [String], startIndexGroups: Int) throws(ConfigurationError) -> [String: String] {
        guard startIndexGroups != 0 else { return [:] }

        guard startIndexGroups <= parameters.count else {
            throw .indexOutOfBounds
        }

        var params: [String: String] = [:]

        for index in 0..<startIndexGroups {
            let current = parameters[index]
            let stringComponents = current.components(separatedBy: "=")

            if stringComponents.count > 1 {
                params[stringComponents[0]] = stringComponents[1]
            }
        }

        return params
    }

    // MARK: - Utils

    typealias RegexType = Regex<Regex<(Substring, Regex<OneOrMore<Substring>.RegexOutput>.RegexOutput)>.RegexOutput>

    private func makeConfigurationRegex(prefix: String, suffix: String) -> RegexType {
        return Regex {
            Anchor.startOfLine
            prefix
            Capture {
                OneOrMore(.word)
            }
            suffix
        }
    }
}
//
//  Configuration.swift
//  Radiacode
//
//  Created by Pavel Marinchenko on 29.05.2023.
//

import Foundation

enum DeviceConfiguration {}

extension DeviceConfiguration {

    struct Section {
        let name: String
        let parameters: [String: String]
        let groups: [Group]
    }

    struct Group {
        let name: String
        let parameters: [String: String]
        let channels: [Channel]
    }

    struct Channel {
        let channelId: String
        let parameters: [String: String]

        /// Размер данных из потока  прибора
        var streamSize: DataType {
            guard let rawType = parameters["DType"],
                  let intType = Int(rawType),
                  let dtype = DataType(rawValue: intType) else { return .unknown }
            return dtype
        }

        /// Размер данных для хранения в приложении
        var storeSize: DataType {
