//
//  GlobalDeviceManager.swift
//  Radiacode
//
//  Created by Pavel Marinchenko on 31.03.2023.
//

import Foundation
import CoreBluetooth
import Combine
import FactoryKit

/// Менеджер устройства
protocol DeviceManager {
    /// Отправка команды
    /// - Parameter command: команда
    /// - Returns: Ответ
    @discardableResult
    func send<T: BluetoothCommand>(command: T) async -> Result<T.Response, Error>
    /// Запуск загрузки данных с прибора
    func startRealTimeData()
    /// Останавливает загрузку данных с прибора
    func cancelRealTimeData()
}

protocol DeviceSetupManager {
    /// Подключено новое устройство
    var connectedDeviceSubject: PassthroughSubject<DeviceManagerImpl.ConnectedDeviceState, Never> { get }
    /// Подключение устройства
    /// - Parameter device: устройство
    func setup(device: BluetoothDevice)
    /// Установка первоначального соединения для выполнения команд
    func setupInitialConnectionObserver()
    /// Устанавливает настройки калибровочных коэффицентов
    /// - Parameter action: коэффициенты
    func setupCalibrationSettings(_ action: EnergyCalibrationCommand.Action.Write) async
    /// Сброс устройства
    func reset() async
    /// Обновляет настройки устройства
    func updateDeviceSettings() async
}

final class DeviceManagerImpl: DeviceManager, DeviceSetupManager {

    enum ConnectedDeviceState {
        case connected
        case updating
        case error
    }

    @WeakLazyInjected(\.spectrumDataRepository) private var spectrumDataRepository
    @WeakLazyInjected(\.spectrogramDataRepository) private var spectrogramDataRepository
    @WeakLazyInjected(\.dataBufferSetupRepository) private var dataBufferSetupRepository
    @WeakLazyInjected(\.activityDataRepository) private var activityDataRepository
    @LazyInjected(\.configurationParser) private var configurationParser
    @Injected(\.settingComposer) private var settingComposer
    @WeakLazyInjected(\.analyticsEngine) private var analyticsEngine
    @WeakLazyInjected(\.firmwareViewModel) private var firmwareViewModel
    @Injected(\.appInfo) private var appInfo
    @Injected(\.deviceContainer) private var deviceContainer

    enum DeviceManagerError: Error {
        case device
    }
    // MARK: Properties

    private var connectedDevice: BluetoothDevice?

    private var deviceCanncelables: AnyCancellable?

    @discardableResult
    func send<T: BluetoothCommand>(command: T) async -> Result<T.Response, Error> {
        guard let connectedDevice else {
            return .failure(DeviceManagerError.device)
        }
        return await connectedDevice.send(command: command)
    }

    let connectedDeviceSubject: PassthroughSubject<DeviceManagerImpl.ConnectedDeviceState, Never> = .init()

    func setup(device: BluetoothDevice) {
        connectedDevice = device
        setupInitialConnectionObserver()
    }

    func setupInitialConnectionObserver() {
        deviceCanncelables?.cancel()
        deviceCanncelables = connectedDevice?.peripheral?.peripheralState
            .dropFirst()
            .filter { $0 == .ready }
            .sink { [weak self] _ in
                guard let self = self, let connectedDevice else { return }
                self.deviceCanncelables = nil
                Task {
                    await connectedDevice.start()
                    await connectedDevice.send(command: SetExchangeCommand())

                    var hadSetupError = false

                    do {
                        try await Task.sleep(milliseconds: 2)

                        try await self.configure(connectedDevice: connectedDevice)

                        await self.getDeviceSettings(connectedDevice: connectedDevice)
                        await self.fetchEnergyCalibration(for: connectedDevice)
                        await connectedDevice.send(command: SetLocalTimeCommand())

                        let timeResult = await connectedDevice.send(command: DeviceTimeCommand())
                        if case .success(let response) = timeResult {
                            connectedDevice.deviceBaseDate = response.date.timeIntervalSince1970
                        }
                    } catch {
                        hadSetupError = true
                        if let error = error as? AnalyticsError {
                            self.analyticsEngine?.reportError(error)
                        }
                        Log.error("Initial setup failed: \(error)")
                    }

                    await self.getFirmwareInfo(connectedDevice: connectedDevice)

                    self.deviceContainer.current = connectedDevice

                    let firmwareState = await self.firmwareViewModel?.checkFirmware(device: connectedDevice, hasError: hadSetupError)

                    if firmwareState != .update {
                        if hadSetupError {
                            await self.reset()
                            self.connectedDeviceSubject.send(.error)
                        } else {
                            self.connectedDeviceSubject.send(.connected)
                        }
                    }
                }
            }
    }

    private func configure(connectedDevice: BluetoothDevice, didRetry: Bool = false) async throws {
        let configResult = await connectedDevice.send(command: ConfigurationCommand())
        do {
            let response = try configResult.get()
            let configurationSettings = try configurationParser.parse(configuration: response)
            connectedDevice.configurationSettings = configurationSettings

            let specFormatVersion = configurationSettings.specFormatVersion
            let disableSpectrum = configurationSettings.disableSpectrum

            await spectrumDataRepository?.setupSpectrumSetting(specFormatVersion: specFormatVersion, spectrumDisabled: disableSpectrum)
            await spectrogramDataRepository?.setupSpectrumSetting(specFormatVersion: specFormatVersion, spectrumDisabled: disableSpectrum)
            await activityDataRepository?.setupSpectrumSetting(specFormatVersion: specFormatVersion, spectrumDisabled: disableSpectrum)

            connectedDevice.alarms.countRate.offScale = configurationSettings.maxCountRate
            connectedDevice.alarms.doseRate.offScale = configurationSettings.maxDoseRate
            connectedDevice.alarms.dose.offScale = configurationSettings.maxDose
        } catch {
            if !didRetry {
                try await configure(connectedDevice: connectedDevice, didRetry: true)
            } else {
                throw error
            }
        }
    }

    func updateDeviceSettings() async {
        guard let connectedDevice else { return }
        await getDeviceSettings(connectedDevice: connectedDevice)
    }

    func setupCalibrationSettings(_ action: EnergyCalibrationCommand.Action.Write) async {
        guard let connectedDevice else { return }
        await connectedDevice.send(command: EnergyCalibrationCommand(action: .write(action)))
        await fetchEnergyCalibration(for: connectedDevice)
    }

    @MainActor
    private func getDeviceSettings(connectedDevice: BluetoothDevice) async {
        let controlResult = await connectedDevice.send(command: SettingsCommand(setting: .deviceControl))
        if case .success(let response) = controlResult {
            await self.settingComposer.set(raw: response.register, value: response.value)
        }

        let soundResult = await connectedDevice.send(command: SettingsCommand(setting: .soundControl))
        if case .success(let response) = soundResult {
            await self.settingComposer.set(raw: response.register, value: response.value)
        }

        let vibroResult = await connectedDevice.send(command: SettingsCommand(setting: .vibroControl))
        if case .success(let response) = vibroResult {
            await self.settingComposer.set(raw: response.register, value: response.value)
        }

        let temperatureUnit = await connectedDevice.send(command: SettingsCommand(setting: .temperatureUnit))
        if case .success(let response) = temperatureUnit {
            connectedDevice.settings.temperatureUnit = TemperatureUnit(rawValue: response.value) ?? .celsius
        }

        connectedDevice.alarms.countRate = await readAlarmLevels(connectedDevice.alarms.countRate, on: connectedDevice)
        connectedDevice.alarms.doseRate = await readAlarmLevels(connectedDevice.alarms.doseRate, on: connectedDevice)
        connectedDevice.alarms.dose = await readAlarmLevels(connectedDevice.alarms.dose, on: connectedDevice)
    }

    private func readAlarmLevels(_ level: Alarm.Level, on device: BluetoothDevice) async -> Alarm.Level {
        let type = level.radiationType
        let multiplier = device.configurationSettings.doseAlarmMultiplier
        let version = device.firmware.firmwareFeatureLevel
        let op1 = type.deviceSettingsLevel1(version: version)
        let op2 = type.deviceSettingsLevel2(version: version)
        var updated = level
        if case .success(let response) = await device.send(command: SettingsCommand(setting: op1)) {
            updated.level1 = op1.decodeAlarm(rawValue: response.value, multiplier: multiplier)
        }
        if case .success(let response) = await device.send(command: SettingsCommand(setting: op2)) {
            updated.level2 = op2.decodeAlarm(rawValue: response.value, multiplier: multiplier)
        }
        return updated
    }

    @MainActor
    private func getFirmwareInfo(connectedDevice: BluetoothDevice) async {
        let versionResult = await connectedDevice.send(command: FirmwareCommand.GetVersion())
        if case .success(let response) = versionResult {
            analyticsEngine?.setupUser(deviceId: appInfo.uniqueDeviceId, radiaCodeDevice: connectedDevice.identifier, firmware: response.target.version)
            connectedDevice.firmware.version = response
        }

        let signatureResult = await connectedDevice.send(command: FirmwareCommand.ReadFlashSiganture())
