import Foundation
import Combine
import FactoryKit

@Observable
final class BluetoothDevice {

    @ObservationIgnored
    @Injected(\.settingComposer) private var settingComposer

    enum BluetoothDeviceError: Error {
        case transmition
    }

    // MARK: Private properties
    @ObservationIgnored
    private var transmition: DeviceTransmition?

    @ObservationIgnored
    private var connectionStateSubscription: AnyCancellable?
    @ObservationIgnored
    private var bluetoothSignalSubscription: AnyCancellable?
    @ObservationIgnored
    private var settingsChangedSubscription: AnyCancellable?

    // MARK: Properties

    /// Устройство
    let radiacode: RadiaCode.Device

    /// Объект для взаимодействия с блютуз протоколом
    let peripheral: Peripheral?

    /// Состояние устройства
    var state: PeripheralImpl.ConnectionState = .disconnected
    /// RSSI
    var signal: BluetoothSignal

    /// Настройки
    var settings: Settings
    /// Прошивка
    var firmware: Firmware
    /// Пороговые значения тревог
    var alarms: Alarm
    /// Настройки спектра
    var spectrumSettings: SpectrumSettings
    /// Настройки устройства
    var configurationSettings: ConfigurationSettings = .default
    /// Базовое установленное прибором время (timeIntervalSince1970)
    var deviceBaseDate: Double = 0.0

    init(
        radiacode: RadiaCode.Device,
        signal: BluetoothSignal,
        peripheral: Peripheral?
    ) {
        self.radiacode = radiacode
        self.signal = signal
        self.peripheral = peripheral

        self.settings = .init()
        self.firmware = .init()
        self.alarms = .init()
        self.spectrumSettings = .init()

        self.setupObservers()
