import Foundation
import Combine
import FactoryKit

/// Менеджер поиска устройств для подключения
protocol DeviceFoundManager {

    /// Observer найденного устройсива
    var foundDeviceObserver: PassthroughSubject<RadiaCode, Error> { get }

    /// Observer состояния поиска
    var observeSearchingState: AnyPublisher<Bool, Never> { get }

    /// Запускает поиск устройств
    func startSearching()

    /// Останавливает поиск устройств
    func stopSearching()
}

/// Реализация менеджера поиска устройств для подключения
final class DeviceFoundManagerImpl: DeviceFoundManager {

    @Injected(\.bluetoothManager) private var bluetoothManager

    var foundDeviceObserver: PassthroughSubject<RadiaCode, Error> = .init()

    var observeSearchingState: AnyPublisher<Bool, Never> {
        bluetoothManager.observeScanningStatus
    }

    private var searchCounter = Counter()
    private var isSearching = false

    private var managerCancellables: Set<AnyCancellable> = .init()

    init() {
        setupObservers()
    }

    func startSearching() {
        Task {
            await searchCounter.increment()
            if !isSearching {
                isSearching = true
                bluetoothManager.startScan()
            }
        }
    }

    func stopSearching() {
        Task {
            await searchCounter.decrement()
            if await searchCounter.value == 0 {
                isSearching = false
                bluetoothManager.stopScan()
            } 
        }
    }

    private func setupObservers() {
        bluetoothManager.observeDevice
            .sink { foundDevice in
                self.foundDeviceObserver.send(foundDevice)
            }.store(in: &managerCancellables)
    }
}
//
//  DeviceConnectionManager.swift
//  Radiacode
//
//  Created by Matvey Kozin on 11.09.2023.
//

import UIKit
import CoreBluetooth
import Combine
import FactoryKit

extension Container {
    var deviceConnectionManager: Factory<DeviceConnectionManager> {
        self { DeviceConnectionManagerImpl() }
            .singleton
    }
}

/// Состояние подключения прибора
typealias DeviceConnectionState = DeviceConnectionManagerImpl.ConnectionState

/// Менеджер подключений
protocol DeviceConnectionManager {

    /// События изменения подключения
    var connectionSubject: CurrentValueSubject<DeviceConnectionState, Never> { get }

    /// Запуск подключения
    func startConnect()

    /// Подключение к устройству
    /// - Parameters:
    ///   - radiacode: устройство
    func connect(radiacode: RadiaCode) async

    /// Ручное отключение от устройства
    func manualDisconnect() async
}

final class DeviceConnectionManagerImpl: DeviceConnectionManager {

    enum DeviceConnectionManagerError: Error {
        case timeout
    }

    /// Состояние подключения прибора
    enum ConnectionState: Equatable, CustomStringConvertible {
        /// Не проинициализированно
        case uninitialized
        /// Отсутсвует
        case empty
        /// Поиск
        case search(String)
        /// Переподключение
        case reconnect
        /// Не найден
        case notFound
        /// Подключен
        case connected
        /// Обновление прошивки
        case updatingFirmware
        /// Готов к использованию
        case ready(BluetoothDevice)
        /// Ошибка подключения
        case error
        /// Отключение от устройства и ошибка переподключения
        case disconnected

        var isConnected: Bool {
            switch self {
            case .connected, .ready, .updatingFirmware:
                true
            default:
                false
            }
        }

        var isReady: Bool {
            switch self {
            case .ready:
                true
            default:
                false
            }
        }

        var description: String {
            switch self {
            case .uninitialized:
                "Uninitialized"
            case .empty:
                "Empty"
            case .search(let device):
                "Search \(device)"
            case .reconnect:
                "Recconnect"
            case .notFound:
                "NotFound"
            case .connected:
                "Connected"
            case .updatingFirmware:
                "Updating"
            case .ready:
                "Ready"
            case .error:
                "Connection Error"
            case .disconnected:
                "Disconnected"
            }
        }

        var readyDevice: BluetoothDevice? {
            if case let .ready(device) = self {
                return device
            }
            return nil
        }
    }

    /// Способ подключения к устройству
    enum ConnectionType: Equatable {
        /// Автоматическое
        case auto
        /// Повторное
        case reconnect
        /// Ручное
        case manual
    }

    @Injected(\.deviceSetupManager) private var deviceSetupManager
    @Injected(\.deviceManager) private var deviceManager
    @Injected(\.deviceFoundManager) private var deviceFoundManager
    @Injected(\.bluetoothManager) private var bluetoothManager
    @Injected(\.analyticsEngine) private var analyticsEngine
    @Injected(\.deviceContainer) private var deviceContainer

    private let queue = DispatchQueue(label: "com.radiacode.ble.connection.timeout")
    private var isSearching = false

    let connectionSubject: CurrentValueSubject<ConnectionState, Never> = .init(.uninitialized)

    private var searchCancellable: AnyCancellable?

    private var cancellable: Set<AnyCancellable> = .init()

    func startConnect() {
        analyticsEngine.reportEvent(DeviceConnectionAnalyticsEvent.startSearching)

        guard let deviceId = deviceContainer.lastSavedDeviceId else {
            connectionSubject.send(.empty)
            return
        }

        cancellable.removeAll()
        connectionSubject.send(.search(deviceId))

        searchCancellable = deviceFoundManager.foundDeviceObserver
            .first(where: { $0.device.identifier == deviceId })
            .timeout(60 * 60, scheduler: queue, customError: { DeviceConnectionManagerError.timeout })
            .sink(
                receiveCompletion: { result in
                    switch result {
                    case .failure:
                        self.stopSearching()
                        self.connectionSubject.send(.notFound)
                    case .finished:
                        break
                    }
                }
                , receiveValue: { radiaCodeDevice in
                    self.searchCancellable = nil
                    self.stopSearching()
                    Task {
                        await self.connect(radiacode: radiaCodeDevice)
                    }
                }
            )
        isSearching = true
        deviceFoundManager.startSearching()
    }

    func connect(radiacode: RadiaCode) async {
        /// Отключение от предыдущего устройства
        await disconnect()

        let bluetoothDevice = BluetoothDevice(
            radiacode: radiacode.device,
            signal: radiacode.signal,
            peripheral: PeripheralImpl(cbPeripheral: radiacode.connection)
        )

        bluetoothDevice.peripheral?.connectionState
            .removeDuplicates()
            .dropFirst(2) /// Игнорируем изначальные состояния Disconnected и Connecting
            .sink { [weak self] state in
                guard let self = self else { return }
                self.analyticsEngine.reportEvent(
                    DeviceConnectionAnalyticsEvent.deviceConnection(identifier: bluetoothDevice.identifier, state: state)
                )
                switch state {
                case .connected:
                    self.connectionSubject.send(.connected)
                case .disconnected:
                    self.deviceManager.cancelRealTimeData()
                    Task {
                        await bluetoothDevice.stopCommands()
                    }
                    self.connectionSubject.send(.reconnect)
                    self.bluetoothManager.setupReconnection(device: radiacode.connection)
                case .connecting:
                    // Автоматическое переподключение
                    self.deviceSetupManager.setupInitialConnectionObserver()
                    self.startReconnectTimeout()
                case .disconnecting:
                    break
                }
            }
            .store(in: &cancellable)

        deviceSetupManager.connectedDeviceSubject
            .receive(on: DispatchQueue.main)
            .sink { [weak self] state in
                guard let self else { return }
                self.cancelReconnectTimeout()
                switch state {
                case .updating:
                    self.connectionSubject.send(.updatingFirmware)
                case .connected:
                    self.connectionSubject.send(.ready(bluetoothDevice))
                case .error:
                    self.connectionSubject.send(.error)
                }
            }
            .store(in: &cancellable)

        /// Сохранение устройства
        deviceContainer.lastSavedDeviceId = bluetoothDevice.identifier
        /// Сохранение устройства в менеджер для доступа к подключенному устройству и его первоначальной инициализации
        deviceSetupManager.setup(device: bluetoothDevice)

        /// Подключение к устройству по блютуз
        bluetoothManager.connect(device: radiacode.connection)
    }

    func manualDisconnect() async {
        connectionSubject.send(.empty)
        await disconnect()
    }

    /// Завершение автопоиска и подключения при необходимости
    private func stopSearching() {
        if isSearching {
            isSearching = false
            deviceFoundManager.stopSearching()
        }
    }

    private func disconnect() async {
        // Отменяем таймер
        cancelReconnectTimeout()

        // Удаляем подписки
        cancellable.removeAll()

        // Останавливаем поиск
        stopSearching()

        if let device = deviceContainer.current, let peripheral = device.peripheral?.cbPeripheral {
            // Удаляем устройство из базы для автоподключения
            deviceContainer.lastSavedDeviceId = nil
            if device.state != .disconnected {
                try? await bluetoothManager.disconnect(device: peripheral)
            }
        }
        await deviceSetupManager.reset()
    }

    private var reconnectTimeoutTask: Task<Void, Never>?

    private func startReconnectTimeout() {
        reconnectTimeoutTask?.cancel()
        reconnectTimeoutTask = Task {
            try? await Task.sleep(seconds: 60 * 10)
            guard !Task.isCancelled else { return }
            self.connectionSubject.send(.disconnected)
        }
    }

    private func cancelReconnectTimeout() {
        reconnectTimeoutTask?.cancel()
        reconnectTimeoutTask = nil
    }
}

