        if headerSize > 0 {
            return
        }

        /// Длина команды
        let lengthOffset = 4
        /// Название команды
        let commandOffset = 4

        /// Вычисление длины команды БЕЗ учета первого слова
        self.estimatedLength = bytes.toBinaryInteger(start: 0)

        self.command = bytes.toBinaryInteger(start: lengthOffset)

